command:
// =========================
// TOWER GENERATOR
// Sandbox Generator
// Requires: Settlement Name Generator macro
// =========================

function roll(sides) {
    return Math.ceil(Math.random() * sides);
}

function tableRoll(value, table) {
    return table.find(row => value >= row.min && value <= row.max);
}

// -------------------------
// NAME
// -------------------------

let settlementName = "Unknown Tower";
let settlementNameFormat = "";
let settlementNameRolls = [];

const nameMacro = game.macros.getName("Settlement Name Generator");

if (nameMacro) {
    await nameMacro.execute();
    settlementName = globalThis.generatedSettlementName ?? "Unknown Tower";
    settlementNameFormat = globalThis.generatedSettlementNameFormat ?? "";
    settlementNameRolls = globalThis.generatedSettlementNameRolls ?? [];
}

// -------------------------
// TABLES
// -------------------------

const abovegroundLevelsTable = [
    { min: 1, max: 1, result: 1 },
{ min: 2, max: 3, result: 2 },
{ min: 4, max: 6, result: 3 },
{ min: 7, max: 9, result: 4 },
{ min: 10, max: 11, result: 5 },
{ min: 12, max: 12, result: 6 }
];

const undergroundLevelsTable = [
    { min: 1, max: 6, result: 0 },
{ min: 7, max: 8, result: 1 },
{ min: 9, max: 10, result: 2 },
{ min: 11, max: 11, result: 3 },
{ min: 12, max: 12, result: 4 }
];

const connections = [
    "Staircase",
"Staircase",
"Staircase",
"Spiral staircase",
"Spiral staircase",
"Spiral staircase",
"Ladder",
"Ladder",
"Elevator",
"Elevator",
"Magic elevator",
"Teleportation portals"
];

const materials = [
    "Cobblestone","Cobblestone","Cobblestone","Cobblestone","Cobblestone",
"Wood","Wood","Wood","Wood","Wood",
"Bricks","Bricks","Bricks",
"Sandstone","Sandstone","Sandstone",
"Limestone","Limestone",
"Marble",
"Metal"
];

const shapes = [
    "Square","Square","Square","Square","Square",
"Round","Round","Round","Round","Round",
"Conical","Conical","Conical",
"Tilted","Tilted","Tilted",
"Asymmetrical",
"S-shaped",
"Stacked",
"Twisted"
];

// -------------------------
// ROLLS
// -------------------------

let aboveRoll = roll(12);
let aboveLevels = tableRoll(aboveRoll, abovegroundLevelsTable).result;

let undergroundRoll = roll(12);
let undergroundLevels = tableRoll(undergroundRoll, undergroundLevelsTable).result;

let hasBottomLevel = undergroundLevels > 0;
let totalLevels = aboveLevels + 1 + undergroundLevels; // ground + above + underground

let connectionRoll = roll(12);
let connection = connections[connectionRoll - 1];

let materialRoll = roll(20);
let material = materials[materialRoll - 1];

let shapeRoll = roll(20);
let shape = shapes[shapeRoll - 1];

let wizardLevelRoll = roll(6);
let wizardLevel = 9 + wizardLevelRoll;

let apprenticeCheck = roll(100);
let hasApprentice = apprenticeCheck <= 25;

let apprenticeLevelRoll = null;
let apprenticeLevel = null;

if (hasApprentice) {
    apprenticeLevelRoll = roll(6);
    apprenticeLevel = apprenticeLevelRoll;
}

// -------------------------
// OUTPUT
// -------------------------

let output = `
<h2>Tower Generator</h2>

<h3>Tower Name</h3>
<p><b>Name:</b> ${settlementName}</p>
<p><b>Format:</b> ${settlementNameFormat}</p>
<ul>
${settlementNameRolls.map(r => `<li>${r}</li>`).join("")}
</ul>

<hr>

<h3>Levels</h3>

<p><b>Aboveground Levels Roll:</b> d12 = ${aboveRoll}</p>
<p><b>Aboveground Levels:</b> ${aboveLevels}</p>

<p><b>Underground Levels Roll:</b> d12 = ${undergroundRoll}</p>
<p><b>Underground Levels:</b> ${undergroundLevels}</p>

<p><b>Ground Level:</b> 1</p>
<p><b>Bottom Level:</b> ${hasBottomLevel ? "Yes, because underground levels exist" : "No"}</p>
<p><b>Total Levels:</b> ${totalLevels}</p>

<hr>

<h3>Level Connection</h3>

<p><b>Connection Roll:</b> d12 = ${connectionRoll}</p>
<p><b>Levels Connected By:</b> ${connection}</p>

<hr>

<h3>Outside Appearance</h3>

<p><b>Material Roll:</b> d20 = ${materialRoll}</p>
<p><b>Material:</b> ${material}</p>

<p><b>Shape Roll:</b> d20 = ${shapeRoll}</p>
<p><b>Shape:</b> ${shape}</p>

<hr>

<h3>Wizard</h3>

<p><b>Wizard Level Roll:</b> 9 + d6 = 9 + ${wizardLevelRoll}</p>
<p><b>Wizard Level:</b> ${wizardLevel}</p>

<p><b>Apprentice Check:</b> d100 = ${apprenticeCheck}</p>
<p><b>Has Apprentice:</b> ${hasApprentice ? "Yes" : "No"}</p>

${hasApprentice ? `
    <p><b>Apprentice Level Roll:</b> d6 = ${apprenticeLevelRoll}</p>
    <p><b>Apprentice Level:</b> ${apprenticeLevel}</p>
    ` : ""}

    <hr>

    <h3>Quick Summary</h3>

    <p>
    <b>${settlementName}</b> is a <b>${shape.toLowerCase()}</b> tower made of
    <b>${material.toLowerCase()}</b>. It has <b>${aboveLevels}</b> aboveground level${aboveLevels === 1 ? "" : "s"},
    <b>1</b> ground level, and <b>${undergroundLevels}</b> underground level${undergroundLevels === 1 ? "" : "s"}.
    The levels are connected by <b>${connection.toLowerCase()}</b>.
    A level <b>${wizardLevel}</b> wizard lives here${hasApprentice ? ` with a level <b>${apprenticeLevel}</b> apprentice` : ""}.
    </p>
    `;
    if (globalThis.currentHexFaction) {
        output += `
        <hr>

        <h3>Faction</h3>

        <p><b>Controlling Faction:</b></p>
        <p>${globalThis.currentHexFaction}</p>
        `;
    }

    ChatMessage.create({
        speaker: ChatMessage.getSpeaker(),
                       content: output
    });
